export interface FestivalInfo {
  name: string;
  description: string;
  significance: string;
  rituals: string[];
  history: string;
  location: string;
  season: string;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

export interface GeneratedImage {
