import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { FestivalInfo } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getFestivalDetails = async (festivalName: string): Promise<FestivalInfo | null> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide comprehensive details about the Indian festival: ${festivalName}. Include its significance, rituals, history, common locations of celebration, and traditional season.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            description: { type: Type.STRING },
            significance: { type: Type.STRING },
            rituals: { type: Type.ARRAY, items: { type: Type.STRING } },
            history: { type: Type.STRING },
            location: { type: Type.STRING },
            season: { type: Type.STRING },
          },
          required: ["name", "description", "significance", "rituals", "history", "location", "season"],
        },
      },
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Error fetching festival details:", error);
    return null;
  }
};

export const chatWithUtsavAI = async (message: string, history: { role: 'user' | 'assistant', content: string }[]) => {
  const ai = getAI();
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: 'You are Utsav, a wise and friendly cultural guide specializing in Indian festivals, traditions, and mythology. You provide evocative, spiritual, and accurate information.',
    },
  });

  // Convert history for the Gemini format (Gemini expects parts)
  // But for simple chats we just pass the new message
  const response = await chat.sendMessage({ message });
  return response.text;
};

export const generateFestivalArt = async (prompt: string): Promise<string | null> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: `A cinematic, high-resolution artistic representation of the festival: ${prompt}. Style: Immersive, elegant, soft glowing lights, traditional Indian heritage blended with modern aesthetic, vibrant colors like saffron, gold, and deep blue.` }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating festival art:", error);
    return null;
  }
};

export const findNearbyFestivals = async (lat?: number, lng?: number) => {
  const ai = getAI();
  const query = "What are the major festivals happening or cultural centers near me?";
  const config: any = {
    tools: [{ googleMaps: {} }],
  };

  if (lat && lng) {
    config.toolConfig = {
      retrievalConfig: {
        latLng: { latitude: lat, longitude: lng }
      }
    };
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: query,
    config,
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return {
    text: response.text,
    sources: sources.map((s: any) => ({
      title: s.maps?.title || "Location",
      uri: s.maps?.uri || "#"
    }))
  };
};

