import React, { useState, useRef, useEffect } from 'react';
import { chatWithUtsavAI } from '../services/geminiService';
import { ChatMessage } from '../types';

export const ChatBot: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: 'Greetings, seeker of culture. I am Utsav. What ancient tradition or vibrant festival can I tell you about today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chatWithUtsavAI(input, messages);
      setMessages(prev => [...prev, { role: 'assistant', content: response || "I seem to have lost my train of thought. Please try again." }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'assistant', content: "Forgive me, the spirits of the web are restless. Try again in a moment." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section id="chat" className="py-24 px-4 bg-stone-900/50">
      <div className="max-w-4xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-5xl font-serif text-amber-100 mb-4">Converse with Utsav AI</h2>
          <p className="text-stone-400 max-w-2xl mx-auto">Ask about the deeper meanings behind rituals, the stories of gods, or the culinary delights of any Indian festival.</p>
        </div>

        <div className="glass rounded-[2rem] border border-white/10 flex flex-col h-[600px] overflow-hidden">
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 scrollbar-hide">
            {messages.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-6 py-4 rounded-3xl ${
                  msg.role === 'user' 
                    ? 'bg-amber-600 text-white rounded-br-none' 
                    : 'bg-stone-800 text-stone-200 rounded-bl-none border border-white/5'
                }`}>
                  <p className="leading-relaxed whitespace-pre-wrap">{msg.content}</p>
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-stone-800 px-6 py-4 rounded-3xl rounded-bl-none border border-white/5">
                  <div className="flex gap-2">
                    <div className="w-2 h-2 bg-amber-500 rounded-full animate-bounce"></div>
                    <div className="w-2 h-2 bg-amber-500 rounded-full animate-bounce delay-100"></div>
                    <div className="w-2 h-2 bg-amber-500 rounded-full animate-bounce delay-200"></div>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-stone-900/80 border-t border-white/5">
            <div className="relative flex items-center">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask about Diwali, Holi, Navratri..."
                className="w-full bg-stone-800 border border-white/10 rounded-full py-4 px-6 pr-14 focus:outline-none focus:ring-2 focus:ring-amber-500/50 transition-all text-white"
              />
              <button 
                onClick={handleSend}
                disabled={isLoading}
                className="absolute right-2 w-10 h-10 bg-amber-500 hover:bg-amber-600 text-stone-950 rounded-full flex items-center justify-center transition-all shadow-lg"
              >
                <i className="fa-solid fa-paper-plane text-sm"></i>
              </button>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

import React, { useState } from 'react';
import { getFestivalDetails, generateFestivalArt } from '../services/geminiService';
import { FestivalInfo } from '../types';
import { FestivalCard } from './FestivalCard';

export const FestivalExplorer: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<{ info: FestivalInfo, image: string } | null>(null);

  const handleExplore = async () => {
    if (!searchTerm.trim()) return;
    setLoading(true);
    try {
      const [info, image] = await Promise.all([
        getFestivalDetails(searchTerm),
        generateFestivalArt(searchTerm)
      ]);
      if (info && image) {
        setResult({ info, image });
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <section id="explore" className="py-24 px-4 bg-stone-950">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-16">
          <h2 className="text-5xl font-serif text-amber-100 mb-6">Explore the Odyssey</h2>
          <p className="text-stone-400 text-lg max-w-3xl mx-auto mb-10">
            Enter the name of any festival—global or local—and let Utsav unveil its mysteries through AI-generated art and cultural wisdom.
          </p>

          <div className="flex flex-col md:flex-row gap-4 max-w-2xl mx-auto">
            <input 
              type="text" 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="e.g. Kumbh Mela, Pongal, Onam..."
              className="flex-1 bg-stone-900 border border-white/10 rounded-2xl py-4 px-6 focus:outline-none focus:ring-2 focus:ring-amber-500/50 transition-all text-white text-lg"
            />
            <button 
              onClick={handleExplore}
              disabled={loading}
              className="px-10 py-4 bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-600 hover:to-orange-700 text-stone-950 font-bold rounded-2xl transition-all shadow-xl disabled:opacity-50"
            >
              {loading ? <i className="fa-solid fa-spinner animate-spin mr-2"></i> : null}
              Manifest
            </button>
          </div>
        </div>

        {loading && (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-16 h-16 border-4 border-amber-500/20 border-t-amber-500 rounded-full animate-spin mb-6"></div>
            <p className="text-amber-500 animate-pulse font-serif italic text-xl">Weaving the threads of tradition...</p>
          </div>
        )}

        {result && !loading && (
          <div className="max-w-4xl mx-auto">
            <FestivalCard festival={result.info} imageUrl={result.image} />
          </div>
        )}

        {!result && !loading && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-12 opacity-40">
            {['Diwali', 'Holi', 'Navratri'].map(f => (
              <div key={f} className="glass p-8 rounded-3xl border border-white/5 text-center cursor-pointer hover:opacity-100 transition-opacity" onClick={() => { setSearchTerm(f); }}>
                <h3 className="text-2xl font-serif text-amber-100">{f}</h3>
                <p className="text-stone-500 text-sm mt-2 italic">Click to manifest</p>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
};

import React, { useState, useEffect } from 'react';
import { findNearbyFestivals } from '../services/geminiService';
import { GroundingSource } from '../types';

export const NearbyFestivals: React.FC = () => {
  const [location, setLocation] = useState<{ lat: number, lng: number } | null>(null);
  const [data, setData] = useState<{ text: string, sources: GroundingSource[] } | null>(null);
  const [loading, setLoading] = useState(false);

  const fetchNearby = async (lat?: number, lng?: number) => {
    setLoading(true);
    try {
      const result = await findNearbyFestivals(lat, lng);
      setData(result);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setLocation(coords);
        fetchNearby(coords.lat, coords.lng);
      },
      () => {
        fetchNearby();
      }
    );
  }, []);

  return (
    <section className="py-24 px-4 bg-stone-900">
      <div className="max-w-6xl mx-auto">
        <div className="flex flex-col md:flex-row items-center gap-12">
          <div className="flex-1">
            <h2 className="text-4xl md:text-5xl font-serif text-amber-100 mb-6 leading-tight">Cultural Pulses <br/><span className="text-amber-500">Near You</span></h2>
            <p className="text-stone-400 mb-8 leading-relaxed">
              Using advanced location grounding, Utsav finds temples, cultural landmarks, and ongoing festivities in your vicinity, connecting you to the pulse of tradition.
            </p>
            {loading ? (
              <div className="space-y-4">
                <div className="h-4 bg-stone-800 rounded w-full animate-pulse"></div>
                <div className="h-4 bg-stone-800 rounded w-5/6 animate-pulse"></div>
                <div className="h-4 bg-stone-800 rounded w-4/6 animate-pulse"></div>
              </div>
            ) : data ? (
              <div className="space-y-6">
                <div className="prose prose-invert max-w-none text-stone-300">
                   {data.text}
                </div>
                {data.sources.length > 0 && (
                  <div>
                    <h4 className="text-sm font-semibold text-amber-500 uppercase tracking-widest mb-3">Verified Sources</h4>
                    <div className="flex flex-wrap gap-3">
                      {data.sources.map((src, i) => (
                        <a 
                          key={i} 
                          href={src.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="px-4 py-2 glass rounded-full text-xs text-amber-200 border border-amber-500/20 hover:bg-amber-500/10 transition-colors"
                        >
                          <i className="fa-solid fa-location-dot mr-2"></i>
                          {src.title}
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ) : (
              <p className="text-stone-500 italic">No cultural data found for your region yet.</p>
            )}
          </div>
          <div className="flex-1 w-full max-w-md">
            <div className="relative aspect-square glass rounded-full flex items-center justify-center p-12 border border-white/10 group">
              <div className="absolute inset-0 bg-amber-500/5 rounded-full blur-3xl group-hover:bg-amber-500/10 transition-all"></div>
              <div className="relative text-center">
                <i className="fa-solid fa-compass text-6xl text-amber-500 mb-6 animate-pulse"></i>
                <h3 className="text-2xl font-serif text-amber-100">Regional Explorer</h3>
                <p className="text-stone-500 text-sm mt-2">AI-guided local insights</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};
